{
  "summary": "This paper rigorously investigates the challenges of true few-shot learning with pretrained language models, defined as learning without access to large validation sets for model selection. It empirically shows that standard model selection methods like cross-validation and MDL perform poorly for prompt and hyperparameter selection in this setting, leading to high variance and degraded performance compared to tuned few-shot learning with validation data.",
  "strengths": [
    {
      "point": "Clear formalization and disambiguation of few-shot learning settings",
      "evidence": "The paper distinguishes between multi-distribution, tuned, and true few-shot learning, clarifying the often conflated scenarios."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple tasks, models, and selection criteria",
      "evidence": "Evaluations include prompt selection on LAMA with 9 models (82M to 175B parameters) and hyperparameter selection on 8 SuperGLUE tasks using ADAPET."
    },
    {
      "point": "Identification of model selection as a fundamental bottleneck in true few-shot learning",
      "evidence": "Results show CV and MDL only marginally outperform random selection and often underperform compared to validation-based tuning, with high variance especially for larger models."
    },
    {
      "point": "Insightful recommendations for future research and evaluation protocols",
      "evidence": "The paper advocates for explicit reporting of hyperparameters, inclusion of validation examples in total counts, and exploration of meta-learning or unsupervised approaches."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of empirical comparison to meta-learning or few-shot adaptation baselines without validation sets",
      "evidence": "While meta-learning is suggested as future work, no experiments compare CV/MDL to such approaches to contextualize the model selection bottleneck."
    },
    {
      "point": "Insufficient justification and exploration of cross-validation methodology",
      "evidence": "Only LOOCV is used without rationale or ablation of other CV variants or bootstrap methods, limiting understanding of selection reliability."
    },
    {
      "point": "Limited details on permutation marginalization and MDL implementation",
      "evidence": "The number of permutations sampled and computational feasibility are unclear; no pseudocode or code is provided for the MDL criterion."
    },
    {
      "point": "Evaluation baselines for prompt selection are limited",
      "evidence": "Random prompt selection is the main baseline; heuristic or learned prompt selection methods without validation sets are not compared."
    },
    {
      "point": "Potential risk of data leakage not fully addressed",
      "evidence": "The paper does not clarify whether held-out test sets are strictly disjoint from data used in prompt or hyperparameter selection."
    },
    {
      "point": "Narrow task and metric scope limits generalizability",
      "evidence": "Evaluations focus on English NLP benchmarks with accuracy and NLL metrics, omitting other task types, languages, modalities, and robustness or calibration metrics."
    },
    {
      "point": "Reproducibility hindered by missing hyperparameter search space details and code",
      "evidence": "Hyperparameter ranges and distributions for ADAPET are not described; no code or pseudocode for MDL is provided."
    },
    {
      "point": "Ambiguities in key definitions and variance reduction attempts",
      "evidence": "The notion of 'large' validation sets is not precisely quantified; variance reduction methods are mentioned but not thoroughly explained."
    },
    {
      "point": "Limited scope focusing only on prompt and hyperparameter selection",
      "evidence": "Other important few-shot aspects like architecture choice, data augmentation, or example selection are not studied."
    },
    {
      "point": "Generalisability to multilingual, multimodal tasks and impact of model scale not fully explored",
      "evidence": "All tasks are English NLP; the interaction between model size and selection difficulty is noted but not systematically analyzed."
    }
  ],
  "questions": [
    {
      "question": "How do meta-learning or few-shot adaptation methods without validation sets compare to CV/MDL for model selection?",
      "motivation": "Understanding this would clarify whether model selection is inherently bottlenecked or if alternative approaches can circumvent the problem."
    },
    {
      "question": "Can weak or noisy validation signals (e.g., unlabeled data or proxy metrics) improve model selection in true few-shot settings?",
      "motivation": "Exploring intermediate scenarios could provide practical solutions between no validation and large validation regimes."
    },
    {
      "question": "How does model size systematically affect the difficulty of model selection without validation data?",
      "motivation": "A detailed analysis could inform whether scaling models exacerbates or mitigates true few-shot learning challenges."
    },
    {
      "question": "What are the computational trade-offs and practical feasibility of marginalizing over training example permutations for larger datasets?",
      "motivation": "Clarifying this would help assess the scalability and applicability of the proposed MDL and CV methods."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
